// Define what a Task looks like — an interface contract
interface Task {
  id: string;
  title: string;
  completed: boolean;
  createdAt: Date;
}
// Generic storage class that persists items to a JSON file
class FileStore<T extends { id: string }> {
  private items: T[] = [];
  constructor(private filePath: string) {}
  // Load items from file
  async load(): Promise<void> {
    try {
      const data: string = await readFile(this.filePath, 'utf-8');
      this.items = JSON.parse(data) as T[];
    } catch {
      this.items = []; // Start fresh if file missing
    }
  }
  // Save current items to file
  async save(): Promise<void> {
    await writeFile(this.filePath, JSON.stringify(this.items, null, 2));
  }
  getAll(): T[] { return this.items; }
  getById(id: string): T | undefined {
    return this.items.find(item => item.id === id);
  }
  add(item: T): void { this.items.push(item); }
  remove(id: string): void {
    this.items = this.items.filter(item => item.id !== id);
  }
}
